function TicTacToe() {
  const [board, setBoard] = React.useState(Array(9).fill(null));
  const [xTurn, setXTurn] = React.useState(true);
  const [scores, setScores] = React.useState({X:0,O:0,draw:0});

  const winner = (()=>{
    const lines=[[0,1,2],[3,4,5],[6,7,8],[0,3,6],[1,4,7],[2,5,8],[0,4,8],[2,4,6]];
    for(const [a,b,c] of lines)if(board[a]&&board[a]===board[b]&&board[a]===board[c])return board[a];
    return board.every(Boolean)?'draw':null;
  })();

  const click = (i)=>{
    if(board[i]||winner)return;
    const b=[...board];b[i]=xTurn?'X':'O';setBoard(b);setXTurn(!xTurn);
  };

  const reset = ()=>{
    if(winner==='draw')setScores(s=>({...s,draw:s.draw+1}));
    else if(winner)setScores(s=>({...s,[winner]:s[winner]+1}));
    setBoard(Array(9).fill(null));setXTurn(true);
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',alignItems:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:8}}>Tic Tac Toe</div>
      <div style={{fontSize:14,color:'#888',marginBottom:12}}>
        {winner?(winner==='draw'?'Draw!':`Winner: ${winner}!`):`${xTurn?'X':'O'}'s turn`}
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(3,60px)',gap:4,marginBottom:16}}>
        {board.map((cell,i)=> (
          <button key={i} onClick={()=>click(i)}
            style={{width:60,height:60,fontSize:24,fontWeight:700,borderRadius:8,border:'1px solid #ccc',background:cell==='X'?'#007AFF15':cell==='O'?'#FF3B3015':'#fff',color:cell==='X'?'#007AFF':'#FF3B30',cursor:'pointer'}}>
            {cell}
          </button>
        ))}
      </div>
      <button onClick={reset}
        style={{padding:'8px 20px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',marginBottom:12}}>
        {winner?'Play Again':'Reset'}
      </button>
      <div style={{display:'flex',gap:16,fontSize:13}}>
        <span style={{color:'#007AFF',fontWeight:600}}>X: {scores.X}</span>
        <span style={{color:'#888'}}>Draw: {scores.draw}</span>
        <span style={{color:'#FF3B30',fontWeight:600}}>O: {scores.O}</span>
      </div>
    </div>
  );
}
render(<TicTacToe/>);
